import React from 'react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { useTheme } from '../ThemeContext';

const weekData = [
  { day: 'Mon', hours: 8.5 },
  { day: 'Tue', hours: 9.0 },
  { day: 'Wed', hours: 7.5 },
  { day: 'Thu', hours: 8.0 },
  { day: 'Fri', hours: 7.0 },
  { day: 'Sat', hours: 0 },
  { day: 'Sun', hours: 0 },
];

export function TimeTrackingCard() {
  const { theme } = useTheme();
  const textMuted = theme === 'dark' ? '#64748b' : '#94a3b8';
  const primary = '#6366f1';

  const todayIndex = new Date().getDay();
  const today = todayIndex === 0 ? 6 : todayIndex - 1;

  return (
    <div className="bg-dash-card border border-dash-border rounded-xl p-5 flex flex-col gap-4 transition-colors duration-200">
      <div className="flex items-center justify-between">
        <h3 className="text-dash-text" style={{ fontSize: '14px', fontWeight: 600 }}>Time Tracking</h3>
        <span className="text-xs text-dash-text-muted">This week</span>
      </div>

      {/* Today summary */}
      <div className="flex items-end gap-3">
        <div>
          <p className="text-dash-text" style={{ fontSize: '30px', fontWeight: 700, lineHeight: 1 }}>
            {weekData[today]?.hours || 0}h
          </p>
          <p className="text-dash-text-muted mt-1" style={{ fontSize: '12px' }}>Today's logged hours</p>
        </div>
        <div className="ml-auto text-right">
          <p className="text-dash-primary" style={{ fontSize: '13px', fontWeight: 600 }}>
            {weekData.reduce((s, d) => s + d.hours, 0)}h
          </p>
          <p className="text-dash-text-muted" style={{ fontSize: '11px' }}>Week total</p>
        </div>
      </div>

      {/* Bar chart */}
      <ResponsiveContainer width="100%" height={80}>
        <BarChart data={weekData} barSize={10} margin={{ top: 0, right: 0, bottom: 0, left: -20 }}>
          <XAxis dataKey="day" tick={{ fontSize: 10, fill: textMuted }} axisLine={false} tickLine={false} />
          <YAxis hide />
          <Tooltip
            contentStyle={{
              background: theme === 'dark' ? '#1e293b' : '#fff',
              border: `1px solid ${theme === 'dark' ? '#334155' : '#e2e8f0'}`,
              borderRadius: '8px',
              fontSize: '12px',
              color: theme === 'dark' ? '#f1f5f9' : '#0f172a',
            }}
            formatter={(v) => [`${v}h`, 'Hours']}
          />
          <Bar dataKey="hours" radius={[4, 4, 0, 0]}>
            {weekData.map((_, i) => (
              <Cell key={i} fill={i === today ? primary : theme === 'dark' ? '#334155' : '#e2e8f0'} />
            ))}
          </Bar>
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
}
